1	const PROCESSING_FEE = 5;
2	
3	const MAIN_ITEM_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	};
9	
10	const COMPONENT_PREMIUM = 25;
11	const COMPONENT_BLOCK_PREMIUM = 60;
12	const COMPONENT_BLOCK_SIZE = 3;
13	
14	const KNOWN_COMPONENT_TYPES = new Set(["rune", "moonstone"]);
15	
16	const isComponent = (type: string): boolean => !MAIN_ITEM_PREMIUMS.hasOwnProperty(type);
17	
18	const isKnownType = (type: string): boolean =>
19	  MAIN_ITEM_PREMIUMS.hasOwnProperty(type) || KNOWN_COMPONENT_TYPES.has(type);
20	
21	const CURSED_SURCHARGE_RATE = 0.5;
22	const HIGH_ENCHANTMENT_THRESHOLD = 5;
23	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
24	
25	const calculateItemSurcharges = (item: { type: string; cursed?: boolean; enchantment?: number }): number => {
26	  const base = MAIN_ITEM_PREMIUMS[item.type] ?? 0;
27	  let surcharges = 0;
28	  if (item.cursed) {
29	    surcharges += base * CURSED_SURCHARGE_RATE;
30	  }
31	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
32	    surcharges += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
33	  }
34	  return surcharges;
35	};
36	
37	const calculateComponentGroupPremium = (count: number): number =>
38	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
39	
40	const FIRST_INSURANCE_RATE = 0.1;
41	const LOYALTY_DISCOUNT_RATE = 0.2;
42	const LOYALTY_THRESHOLD_YEARS = 2;
43	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
44	
45	const calculatePremium = (items: { type: string; cursed?: boolean; enchantment?: number }[], yearsWithMHPCO: number, isFollowUp: boolean): number => {
46	  for (const item of items) {
47	    if (!isKnownType(item.type)) {
48	      throw new Error(`Unknown item type: ${item.type}`);
49	    }
50	  }
51	
52	  let policyBasePremium = 0;
53	  let itemSurcharges = 0;
54	
55	  const componentCounts: Record<string, number> = {};
56	  for (const item of items) {
57	    if (isComponent(item.type)) {
58	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
59	    } else {
60	      policyBasePremium += MAIN_ITEM_PREMIUMS[item.type] ?? 0;
61	      itemSurcharges += calculateItemSurcharges(item);
62	    }
63	  }
64	
65	  for (const count of Object.values(componentCounts)) {
66	    policyBasePremium += calculateComponentGroupPremium(count);
67	  }
68	
69	  const policyModifierRate = FIRST_INSURANCE_RATE
70	    - (yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? LOYALTY_DISCOUNT_RATE : 0)
71	    - (isFollowUp ? FOLLOW_UP_DISCOUNT_RATE : 0);
72	  const policyModifiers = policyBasePremium * policyModifierRate;
73	
74	  return Math.ceil(policyBasePremium + itemSurcharges + policyModifiers + PROCESSING_FEE);
75	};
76	
77	export function processScenario(scenario: { customer: { yearsWithMHPCO: number }; steps: { op: string; items?: { type: string }[] }[] }): { results: unknown[] } {
78	  let quoteCount = 0;
79	  const results = scenario.steps.map((step) => {
80	    const isFollowUp = quoteCount > 0;
81	    quoteCount++;
82	    const premium = calculatePremium(step.items ?? [], scenario.customer.yearsWithMHPCO, isFollowUp);
83	    return { premium };
84	  });
85	  return { results };
86	}
