43	const LOYALTY_DISCOUNT_RATE = 0.2;
44	const LOYALTY_THRESHOLD_YEARS = 2;
45	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
46	
47	const calculatePremium = (items: { type: string; cursed?: boolean; enchantment?: number }[], yearsWithMHPCO: number, isFollowUp: boolean): number => {
48	  for (const item of items) {
49	    if (!isKnownType(item.type)) {
50	      throw new Error(`Unknown item type: ${item.type}`);
51	    }
52	  }
53	
54	  let policyBasePremium = 0;
55	  let itemSurcharges = 0;
56	
57	  const componentCounts: Record<string, number> = {};
58	  for (const item of items) {
59	    if (isComponent(item.type)) {
60	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
61	    } else {
62	      policyBasePremium += MAIN_ITEM_PREMIUMS[item.type] ?? 0;
63	      itemSurcharges += calculateItemSurcharges(item);
64	    }
65	  }
66	
67	  for (const count of Object.values(componentCounts)) {
68	    policyBasePremium += calculateComponentGroupPremium(count);
69	  }
70	
71	  const policyModifierRate = FIRST_INSURANCE_RATE
72	    - (yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? LOYALTY_DISCOUNT_RATE : 0)
73	    - (isFollowUp ? FOLLOW_UP_DISCOUNT_RATE : 0);
74	  const policyModifiers = policyBasePremium * policyModifierRate;
75	
76	  return Math.ceil(policyBasePremium + itemSurcharges + policyModifiers + PROCESSING_FEE);
77	};
78	
79	export function processScenario(scenario: { customer: { yearsWithMHPCO: number }; steps: { op: string; items?: { type: string }[] }[] }): { results: unknown[] } {
80	  let quoteCount = 0;
81	  const results = scenario.steps.map((step) => {
82	    const isFollowUp = quoteCount > 0;
83	    quoteCount++;
84	    const premium = calculatePremium(step.items ?? [], scenario.customer.yearsWithMHPCO, isFollowUp);
85	    return { premium };
86	  });
87	  return { results };
88	}
